#include<bits/stdc++.h>
using namespace std;
int n,a[505],b[505],c=0,k,sum;
int main(){
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>a[i]>>b[i];
		c=max(c,min(a[i],b[i]));
	}
	cin>>k;
	for(int i=c;i>=1;i--){
		sum=0;
		for(int j=0;j<n;j++)
		sum+=(a[j]/i)*(b[j]/i);
		if(sum>=k){
			cout<<i;
			return 0;
		}
	}
}
